import{h as e,am as r,f as i}from"./vue-vendor-BNGP8MTa.js";const a={class:"py-12"},l={__name:"Privacy",setup(o){return(s,t)=>(i(),e("div",a,[...t[0]||(t[0]=[r('<div class="w-full px-4 sm:px-6 md:px-8 lg:px-12 xl:px-16"><div class="max-w-4xl mx-auto"><h1 class="text-4xl font-bold text-gray-900 dark:text-white mb-8">Privacy Policy</h1><div class="prose prose-lg dark:prose-invert max-w-none"><p class="text-gray-600 dark:text-gray-400 mb-6"> Last updated: April 25, 2026 </p><p class="text-gray-600 dark:text-gray-400 mb-4"> This Privacy Policy explains how <strong>Worf Internet Services Private Limited</strong> (&quot;Worf&quot;, &quot;we&quot;, &quot;us&quot;, or &quot;our&quot;) collects, uses, discloses, and protects your personal information when you use the Worf App Store. This policy is compliant with the Information Technology Act, 2000, the Digital Personal Data Protection Act, 2023 (DPDPA), the General Data Protection Regulation (GDPR), and the California Consumer Privacy Act (CCPA). </p><h2 class="text-2xl font-semibold text-gray-900 dark:text-white mt-8 mb-4">1. Information We Collect</h2><p class="text-gray-600 dark:text-gray-400 mb-4"> The Worf App Store collects information you provide directly, including: </p><ul class="list-disc list-inside text-gray-600 dark:text-gray-400 mb-4"><li>Account information (name, email address, password)</li><li>Profile information (company name, bio, avatar)</li><li>Payment information (processed securely through payment partners)</li><li>Application usage data (downloads, ratings, reviews)</li><li>Developer information (for developer accounts)</li><li>Communication preferences</li></ul><h2 class="text-2xl font-semibold text-gray-900 dark:text-white mt-8 mb-4">2. How We Use Your Information</h2><p class="text-gray-600 dark:text-gray-400 mb-4"> We use the information we collect to: </p><ul class="list-disc list-inside text-gray-600 dark:text-gray-400 mb-4"><li>Provide, maintain, and improve our services</li><li>Process transactions and send related information</li><li>Send technical notices and support messages</li><li>Respond to comments and questions</li><li>Monitor and analyze trends, usage, and activities</li><li>Detect, prevent, and address technical issues and fraud</li><li>Comply with legal obligations</li></ul><h2 class="text-2xl font-semibold text-gray-900 dark:text-white mt-8 mb-4">3. Legal Basis for Processing (GDPR)</h2><p class="text-gray-600 dark:text-gray-400 mb-4"> For users in the European Economic Area (EEA), we process your personal data based on the following legal grounds: </p><ul class="list-disc list-inside text-gray-600 dark:text-gray-400 mb-4"><li><strong>Contract Necessity:</strong> To perform our obligations under our Terms of Service</li><li><strong>Legitimate Interest:</strong> To improve our services and prevent fraud</li><li><strong>Consent:</strong> When you provide explicit consent for marketing communications</li><li><strong>Legal Obligation:</strong> To comply with applicable laws</li></ul><h2 class="text-2xl font-semibold text-gray-900 dark:text-white mt-8 mb-4">4. Information Sharing</h2><p class="text-gray-600 dark:text-gray-400 mb-4"> We do not sell your personal information. We may share information in the following circumstances: </p><ul class="list-disc list-inside text-gray-600 dark:text-gray-400 mb-4"><li>With service providers who perform services on our behalf (payment processors, cloud services)</li><li>With developers whose applications you purchase (for licensing and support)</li><li>When required by law or to protect our rights</li><li>With your consent for other purposes</li><li>In connection with a business transfer (merger, acquisition)</li></ul><h2 class="text-2xl font-semibold text-gray-900 dark:text-white mt-8 mb-4">5. International Data Transfers</h2><p class="text-gray-600 dark:text-gray-400 mb-4"> Your information may be transferred to and processed in countries other than India. We ensure appropriate safeguards are in place to protect your data in accordance with GDPR requirements, including Standard Contractual Clauses (SCCs) where required. </p><h2 class="text-2xl font-semibold text-gray-900 dark:text-white mt-8 mb-4">6. Data Security</h2><p class="text-gray-600 dark:text-gray-400 mb-4"> We implement appropriate technical and organizational measures to protect your personal information against unauthorized access, alteration, disclosure, or destruction. These include: </p><ul class="list-disc list-inside text-gray-600 dark:text-gray-400 mb-4"><li>Encryption of data in transit and at rest</li><li>Secure payment processing</li><li>Regular security audits</li><li>Access controls and authentication</li><li>Secure data storage facilities</li></ul><p class="text-gray-600 dark:text-gray-400 mb-4"> However, no method of transmission over the Internet is 100% secure. </p><h2 class="text-2xl font-semibold text-gray-900 dark:text-white mt-8 mb-4">7. Data Retention</h2><p class="text-gray-600 dark:text-gray-400 mb-4"> We retain your personal information for as long as necessary to provide our services and fulfill the purposes outlined in this policy, unless a longer retention period is required or permitted by law. Upon account deletion, your data will be deleted within 30 days, except where required to be retained by law. </p><h2 class="text-2xl font-semibold text-gray-900 dark:text-white mt-8 mb-4">8. Your Rights (GDPR &amp; DPDPA)</h2><p class="text-gray-600 dark:text-gray-400 mb-4"> Under GDPR and DPDPA, you have the right to: </p><ul class="list-disc list-inside text-gray-600 dark:text-gray-400 mb-4"><li><strong>Access:</strong> Request a copy of your personal data</li><li><strong>Rectification:</strong> Correct inaccurate or incomplete data</li><li><strong>Erasure:</strong> Request deletion of your personal data (Right to be Forgotten)</li><li><strong>Portability:</strong> Receive your data in a structured, machine-readable format</li><li><strong>Objection:</strong> Object to processing of your personal data</li><li><strong>Restriction:</strong> Request restriction of processing</li><li><strong>Withdraw Consent:</strong> Withdraw consent at any time</li></ul><h2 class="text-2xl font-semibold text-gray-900 dark:text-white mt-8 mb-4">9. Your Rights (CCPA)</h2><p class="text-gray-600 dark:text-gray-400 mb-4"> For California residents, you have the right to: </p><ul class="list-disc list-inside text-gray-600 dark:text-gray-400 mb-4"><li>Know what personal information we collect about you</li><li>Know whether we sell your personal information</li><li>Request deletion of your personal information</li><li>Opt-out of the sale of personal information</li><li>Non-discrimination for exercising your privacy rights</li></ul><h2 class="text-2xl font-semibold text-gray-900 dark:text-white mt-8 mb-4">10. Cookies</h2><p class="text-gray-600 dark:text-gray-400 mb-4"> We use cookies and similar technologies to improve your experience, analyze usage, and assist in our marketing efforts. You can control cookie settings through your browser preferences. We use: </p><ul class="list-disc list-inside text-gray-600 dark:text-gray-400 mb-4"><li>Essential cookies (required for service functionality)</li><li>Analytics cookies (to understand usage patterns)</li><li>Marketing cookies (with your consent)</li></ul><h2 class="text-2xl font-semibold text-gray-900 dark:text-white mt-8 mb-4">11. Third-Party Services</h2><p class="text-gray-600 dark:text-gray-400 mb-4"> Our service may contain links to third-party websites. We are not responsible for the privacy practices of these third parties. We encourage you to read their privacy policies. </p><h2 class="text-2xl font-semibold text-gray-900 dark:text-white mt-8 mb-4">12. Children&#39;s Privacy</h2><p class="text-gray-600 dark:text-gray-400 mb-4"> Our service is not intended for children under the age of 13. We do not knowingly collect personal information from children under 13. If we become aware that we have collected such information, we will take steps to delete it. </p><h2 class="text-2xl font-semibold text-gray-900 dark:text-white mt-8 mb-4">13. Changes to This Policy</h2><p class="text-gray-600 dark:text-gray-400 mb-4"> We may update our Privacy Policy from time to time. We will notify you of any changes by posting the new policy on this page, updating the &quot;Last updated&quot; date, and sending email notifications for material changes. </p><h2 class="text-2xl font-semibold text-gray-900 dark:text-white mt-8 mb-4">14. Grievance Officer (DPDPA Compliance)</h2><p class="text-gray-600 dark:text-gray-400 mb-4"> In accordance with the Information Technology Act, 2000 and the Digital Personal Data Protection Act, 2023, the name and contact details of the Grievance Officer are as below: </p><p class="text-gray-600 dark:text-gray-400 mb-4"><strong>Grievance Officer:</strong><br> Worf Internet Services Private Limited<br> Email: grievance@worf.cloud<br> Phone: +91 120 492 7985<br> Address: [Registered Office Address]<br> Response Time: Within 30 days of receipt of grievance </p><h2 class="text-2xl font-semibold text-gray-900 dark:text-white mt-8 mb-4">15. Contact Us</h2><p class="text-gray-600 dark:text-gray-400 mb-4"> For questions about this Privacy Policy or to exercise your rights, please contact us at:<br> Email: support@worf.cloud<br> Phone: +91 120 492 7985<br> Website: https://worf.cloud </p></div></div></div>',1)])]))}};export{l as default};
